import{_ as e,o as c,c as r,ai as s}from"./chunks/framework.CQB9ksOm.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ch5/ch5_3.md","filePath":"ch5/ch5_3.md"}'),t={name:"ch5/ch5_3.md"};function d(a,o,n,i,l,p){return c(),r("div",null,[...o[0]||(o[0]=[s('<h2 id="_5-3-docker-compose-常用操作命令" tabindex="-1">5.3 Docker Compose 常用操作命令 <a class="header-anchor" href="#_5-3-docker-compose-常用操作命令" aria-label="Permalink to “5.3 Docker Compose 常用操作命令”">​</a></h2><p>Docker Compose 提供了一系列命令来管理多容器应用：</p><ul><li><strong>启动服务</strong>：<code>docker-compose up -d</code> 会在后台启动所有服务，<code>-d</code> 表示 detached 模式。</li><li><strong>停止服务</strong>：<code>docker-compose down</code> 停止并移除所有容器、网络和卷。</li><li><strong>查看状态</strong>：<code>docker-compose ps</code> 显示各容器的运行状态。</li><li><strong>查看日志</strong>：<code>docker-compose logs</code> 输出容器日志，加 <code>-f</code> 可以跟踪实时日志。</li><li><strong>构建镜像</strong>：如果服务使用本地 Dockerfile，<code>docker-compose build</code> 会重新构建镜像。</li><li><strong>重启服务</strong>：<code>docker-compose restart</code>，重启所有服务或指定服务。。</li><li><strong>单服务操作</strong>：可以针对单个服务执行命令，例如 <code>docker-compose start wordpress</code>。</li></ul><p>这些命令大大简化了多容器应用的管理工作。通过组合使用这些命令，可以轻松控制整个应用的运行状态。</p>',4)])])}const g=e(t,[["render",d]]);export{m as __pageData,g as default};
